import { AboutMeComponent } from '../app/content/about-me/about-me.component';
import { WorkExComponent } from '../app/content/work-ex/work-ex.component';
import { Routes } from '@angular/router';
import { TempComponent } from '../app/content/temp/temp.component';
import { EdQualificationComponent } from '../app/content/ed-qualification/ed-qualification.component';
import { MoocComponent } from '../app/content/mooc/mooc.component';
import { CertificationComponent } from '../app/content/certification/certification.component';

export const routeConfig: Routes = [
    {
        path: '',
        component: AboutMeComponent
    },
    {
        path: 'about-me',
        component: AboutMeComponent,
        children: [
            {
                path: 'home',
                component: TempComponent
            }
        ]
    },
    {
        path: 'work-ex',
        component: WorkExComponent
    },
    {
        path: 'ed-qualification',
        component: EdQualificationComponent
    },
    {
        path: 'mooc',
        component: MoocComponent
    },
    {
        path: 'certification',
        component: CertificationComponent
    }

    
];